SELECT rating, COUNT(*) AS film_count
FROM film
GROUP BY rating;

SELECT store_id, COUNT(DISTINCT film_id) AS distinct_film_count
FROM inventory
GROUP BY store_id;

SELECT f.title, l.name AS original_language
FROM film f
JOIN language l ON f.original_language_id = l.language_id;

SELECT COUNT(*) AS unreturned_rentals
FROM rental
WHERE return_date IS NULL;
